import React from 'react';

const feedbackItems = [
  {
    quote: 'Sam joined the team back in July but it feels like he\'s been with the team for much longer than 5 months. Sam immediately made an impact in various critical areas within MAA. Sam established the first ever IG performance critical alerts in distillery, despite lack of prior experience in alerts. He managed the project with expertise from defining the scope to adding robust documentation.',
    author: 'Vincent Kim',
    title: 'Software Engineer',
    company: 'Meta',
  },
  {
    quote: 'Sam is an incredibly well rounded engineer and excelled at the two key areas I look at when evaluating the prowess of an XFN: skill within their field, and the ability to bring that expertise to a cross functional team and contribute efficiently to move the team towards their goals. Sam is the MAA Youth domain expert and the one person who knows the most in the space.',
    author: 'Dan Hart',
    title: 'Product Growth Analyst',
    company: 'Meta',
  },
  {
    quote: 'Sam played an integral role in the Threads Youth launch, delivering major impact under heavy time pressure. Sam went above and beyond, expanding his work to FB:TH and TOA sign-up as well. He demonstrated technical leadership, was always available as a domain expert, and took radical ownership, resolving ambiguity and driving XFN decisions while working with incomplete information.',
    author: 'Michael Continues',
    title: 'Software Engineer',
    company: 'Meta',
  },
  {
    quote: 'The project would not have been successful without Sam. The aspects that really stood out were his technical delivery and execution excellence, and collaborative leadership. Sam prepared an aggressive execution workback plan that gave me clarity on project timelines, and he delivered on it.',
    author: 'Bradley Wu',
    title: 'Software Engineer',
    company: 'Meta',
  },
  {
    quote: 'Sam\'s deep dive on the controller logic and subsequent execution fixed our imbalance exposure issue which had been ongoing for 5 weeks. Furthermore, his solution improves the Comet/Polaris systems by providing a mechanism for future delegate controller QE exposure gating. He proactively solves issues and provides clear and concise updates.',
    author: 'Joshua Greenfield',
    title: 'Software Engineer',
    company: 'Meta',
  },
  {
    quote: 'Sam was the primary NUX point of contact for the AU U16 Ban project, leading the end-to-end flow and working closely with eng teams across FB, Messenger, and CY. His ability to debug and resolve issues quickly under pressure was clear when he addressed several last-minute bugs and SEVs before and after launch.',
    author: 'Piyush Aggarwal',
    title: 'Software Engineer',
    company: 'Meta',
  },
];

function Feedback() {
  return (
    <section id="feedback">
      <h2 className="section-title">Feedback &amp; Accolades</h2>
      {feedbackItems.map((item, i) => (
        <div className="feedback-item" key={i}>
          <blockquote>"{item.quote}"</blockquote>
          <div className="attribution">
            {item.author}, {item.title} &mdash;{' '}
            <span className="company">{item.company}</span>
          </div>
        </div>
      ))}
    </section>
  );
}

export default Feedback;
